import { defineComponentSlotStyle } from "@yamada-ui/react"

export const tooltipStyle = defineComponentSlotStyle({
  base: {
    content: {
      bg: "bg.float",
      borderColor: "border.muted",
      borderWidth: "1px",
      boxShadow: "sm",
      fontSize: "sm",
      maxW: "xs",
      position: "relative",
      px: "sm",
      py: "xs",
      rounded: "l2",
    },
    positioner: {
      zIndex: "ginyu",
    },
  },
})

export type TooltipStyle = typeof tooltipStyle

import { page, render } from "#test/browser"
import { Tooltip } from "."
import { Text } from "../text"

describe("<Tooltip />", () => {
  test("opens tooltip on pointer enter and closes on pointer leave", async () => {
    const { user } = await render(
      <Tooltip content="Tooltip Hovered">
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    await user.unhover(trigger)

    await vi.waitFor(async () => {
      await expect
        .element(page.getByRole("tooltip").query())
        .not.toBeInTheDocument()
    })
  })

  test("opens tooltip on focus and closes on blur", async () => {
    const { user } = await render(
      <>
        <Tooltip closeOnClick={false} content="Tooltip Hovered">
          <button type="button">Trigger</button>
        </Tooltip>
        <button type="button">Outside</button>
      </>,
    )

    const trigger = page.getByRole("button", { name: "Trigger" })
    const outside = page.getByRole("button", { name: "Outside" })

    await user.click(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    await user.click(outside)

    await vi.waitFor(async () => {
      await expect
        .element(page.getByRole("tooltip").query())
        .not.toBeInTheDocument()
    })
  })

  test("closes tooltip on Escape key", async () => {
    const { user } = await render(
      <Tooltip content="Tooltip Hovered">
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    await user.keyboard("{Escape}")

    await vi.waitFor(async () => {
      await expect
        .element(page.getByRole("tooltip").query())
        .not.toBeInTheDocument()
    })
  })

  test("does not close on Escape when closeOnEsc is false", async () => {
    const { user } = await render(
      <Tooltip closeOnEsc={false} content="Tooltip Hovered">
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    await user.keyboard("{Escape}")

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })
  })

  test("closes tooltip on scroll when closeOnScroll is true", async () => {
    const { user } = await render(
      <Tooltip closeOnScroll content="Tooltip Hovered">
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    document.dispatchEvent(new Event("scroll"))

    await vi.waitFor(async () => {
      await expect
        .element(page.getByRole("tooltip").query())
        .not.toBeInTheDocument()
    })
  })

  test("closes tooltip on click when closeOnClick is true", async () => {
    const { user } = await render(
      <Tooltip content="Tooltip Hovered">
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    await user.click(trigger)

    await vi.waitFor(async () => {
      await expect
        .element(page.getByRole("tooltip").query())
        .not.toBeInTheDocument()
    })
  })

  test("does not open tooltip when disabled", async () => {
    const { user } = await render(
      <Tooltip content="Tooltip Hovered" disabled>
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(
      async () => {
        await expect
          .element(page.getByRole("tooltip").query())
          .not.toBeInTheDocument()
      },
      { timeout: 500 },
    )
  })

  test("does not open on touch pointer events", async () => {
    const { user } = await render(
      <>
        <div
          style={{ height: 12, left: 8, position: "fixed", top: 8, width: 12 }}
          data-testid="pointer-reset"
        />
        <Tooltip content="Tooltip Hovered">
          <Text as="span">Trigger</Text>
        </Tooltip>
      </>,
    )

    await user.hover(page.getByTestId("pointer-reset"))

    const trigger = page.getByText("Trigger")

    trigger.element().dispatchEvent(
      new PointerEvent("pointerover", {
        bubbles: true,
        isPrimary: true,
        pointerId: 1,
        pointerType: "touch",
      }),
    )

    await vi.waitFor(
      async () => {
        await expect
          .element(page.getByRole("tooltip").query())
          .not.toBeInTheDocument()
      },
      { timeout: 500 },
    )
  })

  test("closes tooltip on outside click", async () => {
    const { user } = await render(
      <Tooltip content="Tooltip Hovered">
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    document.body.dispatchEvent(new MouseEvent("mousedown", { bubbles: true }))
    document.body.dispatchEvent(new MouseEvent("mouseup", { bubbles: true }))

    await vi.waitFor(async () => {
      await expect
        .element(page.getByRole("tooltip").query())
        .not.toBeInTheDocument()
    })
  })

  test("closes tooltip on pointer leave from content", async () => {
    const { user } = await render(
      <Tooltip content="Tooltip Hovered">
        <Text as="span">Trigger</Text>
      </Tooltip>,
    )

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    const content = page.getByRole("tooltip")

    content.element().dispatchEvent(
      new PointerEvent("pointerout", {
        bubbles: true,
        pointerType: "mouse",
      }),
    )

    await vi.waitFor(async () => {
      await expect
        .element(page.getByRole("tooltip").query())
        .not.toBeInTheDocument()
    })
  })

  test("handles openDelay and closeDelay", async () => {
    const { user } = await render(
      <>
        <div
          style={{ height: 12, left: 8, position: "fixed", top: 8, width: 12 }}
          data-testid="pointer-reset"
        />
        <Tooltip closeDelay={500} content="Tooltip Hovered" openDelay={500}>
          <Text as="span">Trigger</Text>
        </Tooltip>
      </>,
    )

    await user.hover(page.getByTestId("pointer-reset"))

    const trigger = page.getByText("Trigger")

    await user.hover(trigger)

    await expect
      .element(page.getByRole("tooltip").query(), { timeout: 50 })
      .not.toBeInTheDocument()

    await expect
      .element(page.getByRole("tooltip"), { timeout: 5000 })
      .toBeInTheDocument()

    await user.unhover(trigger)

    await expect
      .element(page.getByRole("tooltip"), { timeout: 50 })
      .toBeInTheDocument()

    await expect
      .element(page.getByRole("tooltip").query(), { timeout: 5000 })
      .not.toBeInTheDocument()
  })

  test("force closes when re-opening while already open", async () => {
    const { user } = await render(
      <Tooltip content="Tooltip Hovered">
        <button type="button">Trigger</button>
      </Tooltip>,
    )

    const trigger = page.getByRole("button", { name: "Trigger" })

    await user.hover(trigger)

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })

    trigger.element().dispatchEvent(
      new PointerEvent("pointerover", {
        bubbles: true,
        pointerType: "mouse",
      }),
    )

    await vi.waitFor(async () => {
      await expect.element(page.getByRole("tooltip")).toBeInTheDocument()
    })
  })
})

"use client"

import type { FC, PropsWithChildren, ReactNode } from "react"
import type { HTMLProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { HTMLMotionProps } from "../motion"
import type { UsePopupAnimationProps } from "../popover"
import type { PortalProps } from "../portal"
import type { TooltipStyle } from "./tooltip.style"
import type { UseTooltipProps } from "./use-tooltip"
import { AnimatePresence } from "motion/react"
import { createSlotComponent, cast } from "@yamada-ui/react"
import { motion } from "../motion"
import { usePopupAnimationProps } from "../popover"
import { Portal } from "../portal"
import { tooltipStyle } from "./tooltip.style"
import { useTooltip } from "./use-tooltip"

export interface TooltipProps
  extends
    UseTooltipProps,
    PropsWithChildren,
    UsePopupAnimationProps,
    ThemeProps<TooltipStyle> {
  /**
   * The content of the tooltip.
   */
  content?: ReactNode
  /**
   * The animation duration.
   *
   * @default 0.1
   */
  duration?: UsePopupAnimationProps["duration"]
  /**
   * Props for content element.
   */
  contentProps?: HTMLMotionProps
  /**
   * Props for portal component.
   */
  portalProps?: Omit<PortalProps, "children">
}

const {
  PropsContext: TooltipPropsContext,
  StyleContext,
  usePropsContext: useTooltipPropsContext,
  withContext,
  useRootComponentProps,
} = createSlotComponent<TooltipProps, TooltipStyle>("tooltip", tooltipStyle)

export { TooltipPropsContext, useTooltipPropsContext }

/**
 * `Tooltip` is a component that displays short information, such as supplementary details for an element.
 *
 * @see https://yamada-ui.com/docs/components/tooltip
 */
export const Tooltip: FC<TooltipProps> = (props) => {
  const [
    context,
    {
      animationScheme = "scale",
      children,
      content,
      duration = 0.1,
      contentProps,
      portalProps,
      ...rest
    },
  ] = useRootComponentProps(props)
  const { open, getContentProps, getPositionerProps, getTriggerProps } =
    useTooltip(rest)
  const popupAnimationProps = usePopupAnimationProps({
    animationScheme,
    duration,
  })

  if (!content) return children

  return (
    <StyleContext value={context}>
      <TooltipTrigger asChild {...getTriggerProps()}>
        {children}
      </TooltipTrigger>

      <AnimatePresence>
        {open ? (
          <Portal {...portalProps}>
            <TooltipPositioner {...getPositionerProps()}>
              <TooltipContent
                {...popupAnimationProps}
                {...cast<HTMLMotionProps>(
                  getContentProps(cast<HTMLProps>(contentProps)),
                )}
              >
                {content}
              </TooltipContent>
            </TooltipPositioner>
          </Portal>
        ) : null}
      </AnimatePresence>
    </StyleContext>
  )
}

interface TooltipPositionerProps extends HTMLStyledProps {}

const TooltipPositioner = withContext<"div", TooltipPositionerProps>(
  "div",
  "positioner",
)()

interface TooltipTriggerProps extends HTMLStyledProps<"button"> {}

const TooltipTrigger = withContext<"button", TooltipTriggerProps>(
  "button",
  "trigger",
)()

interface TooltipContentProps extends Omit<
  HTMLMotionProps,
  "children" | "offset" | "transform"
> {}

const TooltipContent = withContext<"div", TooltipContentProps>(
  motion.div,
  "content",
)()

"use client"

import type { PointerEvent } from "react"
import type { PropGetter, Dict } from "@yamada-ui/react"
import type { UseDisclosureProps } from "../../hooks/use-disclosure"
import type { UsePopperProps } from "../../hooks/use-popper"
import { useCallback, useId, useRef } from "react"
import {
  mergeProps,
  useSplitProps,
  dataAttr,
  getDocument,
  getWindow,
  handlerAll,
  useUnmountEffect,
} from "@yamada-ui/react"
import { useDisclosure } from "../../hooks/use-disclosure"
import { useEventListener } from "../../hooks/use-event-listener"
import { useOutsideClick } from "../../hooks/use-outside-click"
import { popperProps, usePopper, usePopperProps } from "../../hooks/use-popper"

export interface UseTooltipProps
  extends Omit<UseDisclosureProps, "timing">, UsePopperProps<"button"> {
  /**
   * The delay before hiding the tooltip.
   *
   * @default 100
   */
  closeDelay?: number
  /**
   * If `true`, the tooltip will hide on click.
   *
   * @default true
   */
  closeOnClick?: boolean
  /**
   * If `true`, the tooltip will hide on pressing Esc key.
   *
   * @default true
   */
  closeOnEsc?: boolean
  /**
   * If `true`, the tooltip will hide on scroll.
   *
   * @default false
   */
  closeOnScroll?: boolean
  /**
   * If `true`, the tooltip will be disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * The delay before showing the tooltip.
   *
   * @default 400
   */
  openDelay?: number
}

export const useTooltip = (props: UseTooltipProps = {}) => {
  const [
    popperProps,
    {
      closeDelay = 0,
      closeOnClick = true,
      closeOnEsc = true,
      closeOnScroll,
      defaultOpen,
      disabled,
      open: openProp,
      openDelay = 0,
      onClose: onCloseProp,
      onOpen: onOpenProp,
    },
  ] = usePopperProps(props, ["open"])
  const describedbyId = useId()
  const triggerRef = useRef<HTMLButtonElement>(null)
  const openTimeout = useRef<NodeJS.Timeout>(undefined)
  const closeTimeout = useRef<NodeJS.Timeout>(undefined)
  const { open, onClose, onOpen } = useDisclosure({
    defaultOpen,
    open: openProp,
    onClose: onCloseProp,
    onOpen: onOpenProp,
  })
  const { getPopperProps, getReferenceProps } = usePopper({
    open,
    ...popperProps,
  })

  const onForceClose = useCallback(() => {
    if (closeTimeout.current) {
      clearTimeout(closeTimeout.current)

      closeTimeout.current = undefined
    }

    onClose()
  }, [onClose])

  const onDelayOpen = useCallback(() => {
    if (!disabled && !openTimeout.current) {
      if (open) onForceClose()

      openTimeout.current = getWindow(triggerRef.current).setTimeout(
        onOpen,
        openDelay,
      )
    }
  }, [disabled, open, onForceClose, onOpen, openDelay])

  const onDelayClose = useCallback(() => {
    if (openTimeout.current) {
      clearTimeout(openTimeout.current)
      openTimeout.current = undefined
    }

    closeTimeout.current = getWindow(triggerRef.current).setTimeout(() => {
      onForceClose()
    }, closeDelay)
  }, [closeDelay, onForceClose])

  useEventListener(
    () => getDocument(triggerRef.current),
    "keydown",
    ({ key }) => {
      if (closeOnEsc && key === "Escape") onDelayClose()
    },
  )

  useEventListener(
    () => getDocument(triggerRef.current),
    "scroll",
    () => {
      if (open && closeOnScroll) onForceClose()
    },
  )

  useOutsideClick({
    ref: triggerRef,
    enabled: open,
    handler: () => {
      onDelayClose()
    },
  })

  useUnmountEffect(() => {
    clearTimeout(openTimeout.current)
    clearTimeout(closeTimeout.current)
  })

  const getTriggerProps: PropGetter<"button"> = useCallback(
    (props = {}) => {
      return getReferenceProps(
        mergeProps(
          props,
          {
            ref: triggerRef,
            "aria-describedby": open ? describedbyId : undefined,
          },
          {
            onBlur: onDelayClose,
            onClick: closeOnClick ? onDelayClose : undefined,
            onFocus: onDelayOpen,
            onPointerEnter: (ev: PointerEvent<HTMLButtonElement>) => {
              if (ev.pointerType !== "touch") onDelayOpen()
            },
            onPointerLeave: (ev: PointerEvent<HTMLButtonElement>) => {
              if (ev.pointerType !== "touch") onDelayClose()
            },
          },
        )(),
      )
    },
    [
      getReferenceProps,
      describedbyId,
      onDelayOpen,
      open,
      closeOnClick,
      onDelayClose,
    ],
  )

  const getPositionerProps: PropGetter = useCallback(
    (props) => {
      return getPopperProps(props)
    },
    [getPopperProps],
  )

  const getContentProps: PropGetter = useCallback(
    (props = {}) => ({
      id: describedbyId,
      "data-close": dataAttr(!open),
      "data-open": dataAttr(open),
      role: "tooltip",
      onPointerLeave: handlerAll(props.onPointerLeave, onDelayClose),
      ...props,
    }),
    [describedbyId, onDelayClose, open],
  )

  return {
    open,
    getContentProps,
    getPositionerProps,
    getTriggerProps,
    onClose: onForceClose,
    onDelayClose,
    onDelayOpen,
    onOpen,
  }
}

export type UseTooltipReturn = ReturnType<typeof useTooltip>

export const tooltipProps: (keyof UseTooltipProps)[] = [
  ...popperProps,
  "open",
  "defaultOpen",
  "onOpen",
  "onClose",
  "closeDelay",
  "closeOnClick",
  "closeOnEsc",
  "closeOnScroll",
  "disabled",
  "openDelay",
]

export const useTooltipProps = <
  Y extends Dict = Dict,
  M extends keyof UseTooltipProps = keyof UseTooltipProps,
>(
  props: Y,
  omitKeys?: M[],
) => {
  return useSplitProps(
    props,
    tooltipProps.filter((key) => !omitKeys?.includes(key as M)),
  ) as unknown as [
    keyof UseTooltipProps extends M
      ? UseTooltipProps
      : Omit<UseTooltipProps, M>,
    Omit<
      Y,
      keyof UseTooltipProps extends M
        ? keyof UseTooltipProps
        : Exclude<keyof UseTooltipProps, M>
    >,
  ]
}
